import pytest
import time
from <helper_fn> import make_authed_request

@pytest.fixture
def token(fresh_user_token):
    return fresh_user_token

def test_requests_below_limit_succeed(token):
    responses = []
    start = time.monotonic()
    for _ in range(59):
        r = make_authed_request("GET", "/api/v1/accounts", token=token)
        responses.append(r)
    elapsed = time.monotonic() - start
    assert elapsed < 60, "59 requests must complete within one window"
    for i, r in enumerate(responses):
        assert r.status_code in range(200, 300), (
            f"Request {i+1} expected 2xx, got {r.status_code}"
        )
        assert "Retry-After" not in r.headers, (
            f"Request {i+1} must not carry Retry-After"
        )

